def updateEnable(startXmitter, endXmitter, doEnable):
	if startXmitter < 10 and endXmitter < 10:
		for x in range(startXmitter+1, endXmitter+1):
			base_path='/'.join(tagPath.split('/')[:-1])
			base_list=[
			base_path + "/Xmitter_0" + str(x) + ".Enabled"
			]
			system.tag.writeAsync(base_list,[doEnable])
	elif startXmitter < 10 and endXmitter >= 10:
		for x in range(startXmitter+1, 10):
			base_path='/'.join(tagPath.split('/')[:-1])
			base_list=[
			base_path + "/Xmitter_0" + str(x) + ".Enabled"
			]
			system.tag.writeAsync(base_list,[doEnable])
		for x in range(10, endXmitter+1):
			base_path='/'.join(tagPath.split('/')[:-1])
			base_list=[
			base_path + "/Xmitter_" + str(x) + ".Enabled"
			]
			system.tag.writeAsync(base_list,[doEnable])
	else:
		for x in range(startXmitter+1, endXmitter+1):
			base_path='/'.join(tagPath.split('/')[:-1])
			base_list=[
			base_path + "/Xmitter_" + str(x) + ".Enabled"
			]
			system.tag.writeAsync(base_list,[doEnable])

if initialChange:
	updateEnable(0,int(currentValue.value),True)
elif previousValue.value < currentValue.value:
	updateEnable(int(previousValue.value),int(currentValue.value),True)
elif initialChange or previousValue.value > currentValue.value:
	updateEnable(int(currentValue.value),int(previousValue.value), False)
